// Time:  O(nlogn)
// Space: O(n)

class Solution {
public:
    vector<vector<string>> groupStrings(vector<string>& strings) {
        unordered_map<string, multiset<string>> groups;
        for (const auto& str : strings) {  // Grouping.
            groups[hashStr(str)].insert(str);
        }

        vector<vector<string>> result;
        for (const auto& kvp : groups) {
            vector<string> group;
            for (auto& str : kvp.second) {  // Sorted in a group.
                group.emplace_back(move(str));
            }
            result.emplace_back(move(group));
        }

        return result;
    }

    string hashStr(string str) {
        const char base = str[0];
        for (auto& c : str) {
            c = 'a' + ((c - base) >= 0 ? c - base : c - base + 26);
        }
        return str;
    }
};

# Time:  O(nlogn)
# Space: O(n)

import collections


class Solution(object):
    # @param {string[]} strings
    # @return {string[][]}
    def groupStrings(self, strings):
        groups = collections.defaultdict(list)
        for s in strings:  # Grouping.
            groups[self.hashStr(s)].append(s)

        result = []
        for key, val in groups.iteritems():
            result.append(sorted(val))

        return result

    def hashStr(self, s):
        base = ord(s[0])
        hashcode = ""
        for i in xrange(len(s)):
            if ord(s[i]) - base >= 0:
                hashcode += unichr(ord('a') + ord(s[i]) - base)
            else:
                hashcode += unichr(ord('a') + ord(s[i]) - base + 26)
        return hashcode
